import{_ as o,o as r,c as a,ag as l}from"./chunks/framework.BWGJuBbb.js";const b=JSON.parse('{"title":"문제 해결 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"tips/troubleshooting.md","filePath":"tips/troubleshooting.md","lastUpdated":1773586478000}'),d={name:"tips/troubleshooting.md"};function e(i,t,s,h,n,c){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="문제-해결-가이드" tabindex="-1">문제 해결 가이드 <a class="header-anchor" href="#문제-해결-가이드" aria-label="Permalink to &quot;문제 해결 가이드&quot;">​</a></h1><blockquote><p>문제가 생겼을 때 당황하지 마세요. 대부분의 문제는 간단한 조치로 해결됩니다. 증상별로 원인과 해결 방법을 정리했습니다.</p></blockquote><div class="tip custom-block"><p class="custom-block-title">먼저 시도해 보세요</p><p>어떤 문제든 아래 3가지를 먼저 시도하면 절반 이상 해결됩니다.</p><ol><li>Claude Desktop을 완전히 종료하고 다시 실행</li><li>인터넷 연결 상태 확인</li><li>앱을 최신 버전으로 업데이트</li></ol></div><h2 id="설치-접속-문제" tabindex="-1">설치 &amp; 접속 문제 <a class="header-anchor" href="#설치-접속-문제" aria-label="Permalink to &quot;설치 &amp; 접속 문제&quot;">​</a></h2><h3 id="claude-desktop이-설치되지-않아요" tabindex="-1"><strong>Claude Desktop이 설치되지 않아요</strong> <a class="header-anchor" href="#claude-desktop이-설치되지-않아요" aria-label="Permalink to &quot;**Claude Desktop이 설치되지 않아요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>설치 파일 실행 시 오류 발생 또는 설치가 진행되지 않음</td></tr><tr><td>원인</td><td>시스템 요구사항 미충족, 보안 소프트웨어 차단, 디스크 용량 부족</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>시스템 요구사항을 확인하세요 (Windows 10 이상, macOS 12 이상)</li><li>디스크 여유 공간이 최소 500MB 이상인지 확인하세요</li><li>회사 보안 프로그램(백신, DLP 등)이 설치를 차단하고 있다면, IT 부서에 설치 허용을 요청하세요</li><li>관리자 권한으로 설치 파일을 실행하세요 (Windows: 우클릭 → 관리자 권한으로 실행)</li><li>기존 설치 파일을 삭제한 후 <a href="https://claude.ai/download" target="_blank" rel="noreferrer">claude.ai/download</a>에서 최신 버전을 다시 다운로드하세요</li></ol><div class="warning custom-block"><p class="custom-block-title">회사 컴퓨터의 경우</p><p>회사 보안 정책으로 프로그램 설치가 제한된 환경에서는 반드시 IT 부서의 승인을 먼저 받으세요.</p></div><p><strong>그래도 안 되면:</strong> IT 부서에 설치 로그 파일을 첨부하여 지원을 요청하세요.</p><hr><h3 id="로그인이-안-돼요" tabindex="-1"><strong>로그인이 안 돼요</strong> <a class="header-anchor" href="#로그인이-안-돼요" aria-label="Permalink to &quot;**로그인이 안 돼요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>로그인 버튼을 눌러도 반응이 없거나, 인증 페이지가 열리지 않음</td></tr><tr><td>원인</td><td>브라우저 문제, 네트워크 차단, 계정 문제</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>기본 브라우저가 정상 작동하는지 확인하세요</li><li><a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a>에 웹 브라우저로 직접 접속하여 로그인이 되는지 테스트하세요</li><li>회사 방화벽이 <code>*.anthropic.com</code>, <code>*.claude.ai</code> 도메인을 차단하고 있지 않은지 확인하세요</li><li>VPN을 사용 중이라면 일시적으로 해제 후 다시 시도하세요</li><li>Claude Desktop 앱의 캐시를 삭제한 후 재시작하세요</li></ol><p><strong>그래도 안 되면:</strong> <a href="https://support.anthropic.com" target="_blank" rel="noreferrer">support.anthropic.com</a>에서 계정 관련 문의를 접수하세요.</p><hr><h3 id="cowork-탭이-보이지-않아요" tabindex="-1"><strong>Cowork 탭이 보이지 않아요</strong> <a class="header-anchor" href="#cowork-탭이-보이지-않아요" aria-label="Permalink to &quot;**Cowork 탭이 보이지 않아요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>Claude Desktop에 Cowork 관련 메뉴나 탭이 표시되지 않음</td></tr><tr><td>원인</td><td>무료 플랜 사용 중, 앱 버전이 오래됨, 기능이 비활성화 상태</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>현재 사용 중인 플랜을 확인하세요 — Cowork 기능은 <strong>Pro 이상</strong>에서 사용 가능합니다</li><li>Claude Desktop을 최신 버전으로 업데이트하세요</li><li>설정(Settings) → 기능(Features)에서 Cowork 관련 토글이 켜져 있는지 확인하세요</li><li>앱을 완전히 종료 후 재시작하세요</li></ol><p><strong>그래도 안 되면:</strong> 플랜 정보와 앱 버전을 확인한 후 고객지원에 문의하세요.</p><hr><h3 id="연결할-수-없습니다-오류" tabindex="-1"><strong>&quot;연결할 수 없습니다&quot; 오류</strong> <a class="header-anchor" href="#연결할-수-없습니다-오류" aria-label="Permalink to &quot;**&quot;연결할 수 없습니다&quot; 오류**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>대화 시도 시 &quot;서버에 연결할 수 없습니다&quot; 또는 네트워크 오류 메시지 표시</td></tr><tr><td>원인</td><td>인터넷 연결 끊김, 서버 점검 중, 방화벽 차단</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>인터넷 연결 상태를 확인하세요 — 웹 브라우저에서 다른 사이트가 열리는지 테스트</li><li><a href="https://status.anthropic.com" target="_blank" rel="noreferrer">status.anthropic.com</a>에서 서버 상태를 확인하세요</li><li>Wi-Fi를 끄고 다시 연결하거나, 유선 연결로 전환해 보세요</li><li>프록시 또는 VPN 설정을 확인하세요</li><li>방화벽에서 Claude Desktop의 네트워크 접근을 허용하세요</li></ol><div class="tip custom-block"><p class="custom-block-title">서버 점검인 경우</p><p>Anthropic은 간헐적으로 서버 점검을 진행합니다. <a href="https://status.anthropic.com" target="_blank" rel="noreferrer">status.anthropic.com</a>에서 점검 일정을 확인하고, 잠시 후 다시 시도하세요.</p></div><p><strong>그래도 안 되면:</strong> 네트워크 환경 정보(프록시 사용 여부, VPN 등)를 포함하여 IT 부서 또는 고객지원에 문의하세요.</p><hr><h2 id="파일-관련-문제" tabindex="-1">파일 관련 문제 <a class="header-anchor" href="#파일-관련-문제" aria-label="Permalink to &quot;파일 관련 문제&quot;">​</a></h2><h3 id="파일을-읽지-못해요" tabindex="-1"><strong>파일을 읽지 못해요</strong> <a class="header-anchor" href="#파일을-읽지-못해요" aria-label="Permalink to &quot;**파일을 읽지 못해요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>파일 이름을 알려줬는데 &quot;파일을 찾을 수 없습니다&quot;라고 응답</td></tr><tr><td>원인</td><td>파일 경로 오류, 파일 이름 오타, 지원하지 않는 파일 형식</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>파일 이름과 확장자를 정확히 입력했는지 확인하세요</li><li>파일의 전체 경로를 알려주세요 (예: <code>C:\\Users\\홍길동\\Documents\\보고서.xlsx</code>)</li><li>파일 탐색기에서 파일이 실제로 존재하는지 확인하세요</li><li>&quot;내 문서 폴더에서 &#39;매출&#39;이 들어간 파일을 찾아줘&quot;라고 요청해 보세요</li><li>파일이 다른 프로그램에서 열려 있다면 닫은 후 다시 시도하세요</li></ol><p><strong>그래도 안 되면:</strong> 파일 경로를 복사하여 대화창에 직접 붙여넣기 해 보세요.</p><hr><h3 id="접근-권한이-없습니다-오류" tabindex="-1"><strong>&quot;접근 권한이 없습니다&quot; 오류</strong> <a class="header-anchor" href="#접근-권한이-없습니다-오류" aria-label="Permalink to &quot;**&quot;접근 권한이 없습니다&quot; 오류**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>파일에 접근하려 하면 권한 오류 메시지 표시</td></tr><tr><td>원인</td><td>파일/폴더 권한 설정, Claude Desktop에 파일 접근 권한 미부여</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>Claude Desktop의 설정에서 <strong>파일 접근 허용 폴더</strong> 목록을 확인하세요</li><li>해당 파일이 포함된 폴더를 허용 목록에 추가하세요</li><li>파일이 읽기 전용으로 설정되어 있다면, 파일 속성에서 읽기 전용을 해제하세요</li><li>네트워크 드라이브의 파일인 경우, 로컬에 복사한 후 시도하세요</li></ol><div class="danger custom-block"><p class="custom-block-title">보안 주의</p><p>회사 보안 폴더나 암호화된 드라이브의 파일은 의도적으로 접근이 제한될 수 있습니다. 무분별하게 권한을 변경하지 마세요.</p></div><p><strong>그래도 안 되면:</strong> 해당 파일을 허용된 폴더(예: 바탕화면, 내 문서)로 복사한 후 다시 시도하세요.</p><hr><h3 id="파일을-저장하지-못해요" tabindex="-1"><strong>파일을 저장하지 못해요</strong> <a class="header-anchor" href="#파일을-저장하지-못해요" aria-label="Permalink to &quot;**파일을 저장하지 못해요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>Claude가 파일을 생성하거나 수정한 후 저장에 실패</td></tr><tr><td>원인</td><td>쓰기 권한 없음, 디스크 용량 부족, 파일이 다른 프로그램에서 사용 중</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>저장할 폴더에 쓰기 권한이 있는지 확인하세요</li><li>디스크 여유 공간을 확인하세요</li><li>같은 이름의 파일이 다른 프로그램(엑셀, 워드 등)에서 열려 있다면 닫으세요</li><li>다른 폴더(예: 바탕화면)에 저장해 보세요</li><li>파일 이름에 특수문자(<code>\\</code>, <code>/</code>, <code>*</code>, <code>?</code> 등)가 포함되어 있지 않은지 확인하세요</li></ol><p><strong>그래도 안 되면:</strong> Claude에게 내용을 대화창에 출력하도록 요청한 후 직접 복사하여 저장하세요.</p><hr><h3 id="엑셀-파일을-열-수-없어요" tabindex="-1"><strong>엑셀 파일을 열 수 없어요</strong> <a class="header-anchor" href="#엑셀-파일을-열-수-없어요" aria-label="Permalink to &quot;**엑셀 파일을 열 수 없어요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td><code>.xlsx</code> 파일을 읽으라고 했는데 내용을 읽지 못하거나 깨진 데이터를 표시</td></tr><tr><td>원인</td><td>파일이 암호로 보호됨, 매크로/VBA 포함, 파일 손상</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>파일에 <strong>비밀번호가 설정</strong>되어 있다면, 엑셀에서 비밀번호를 해제한 후 다시 저장하세요</li><li><code>.xlsm</code> (매크로 포함) 파일은 <code>.xlsx</code>로 다시 저장한 후 시도하세요</li><li>파일 크기가 너무 크다면(50MB 이상), 필요한 시트만 별도 파일로 저장하세요</li><li><code>.csv</code>로 변환하여 시도하면 더 안정적으로 읽힙니다</li></ol><div class="tip custom-block"><p class="custom-block-title">CSV 변환 방법</p><p>엑셀에서 파일 → 다른 이름으로 저장 → 파일 형식을 &quot;CSV (쉼표로 분리)&quot;로 선택하세요.</p></div><p><strong>그래도 안 되면:</strong> 필요한 데이터 범위를 선택하여 새 엑셀 파일에 붙여넣기 후 시도하세요.</p><hr><h3 id="한글-hwp-파일이-안-열려요" tabindex="-1"><strong>한글(.hwp) 파일이 안 열려요</strong> <a class="header-anchor" href="#한글-hwp-파일이-안-열려요" aria-label="Permalink to &quot;**한글(.hwp) 파일이 안 열려요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td><code>.hwp</code> 또는 <code>.hwpx</code> 파일을 읽으라고 했는데 내용을 표시하지 못함</td></tr><tr><td>원인</td><td>HWP는 한글과컴퓨터 고유 포맷으로, 직접 지원이 제한적</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>한글 프로그램에서 해당 파일을 열고 <strong>다른 이름으로 저장</strong> → <code>.docx</code> 또는 <code>.pdf</code>로 변환하세요</li><li>변환된 파일을 Claude에게 전달하세요</li><li>간단한 문서라면 한글에서 텍스트를 복사하여 대화창에 붙여넣기 하세요</li><li><code>.hwpx</code> 형식(한글 2014 이상)이 <code>.hwp</code>보다 호환성이 좋으니, 가능하면 <code>.hwpx</code>로 저장하세요</li></ol><div class="warning custom-block"><p class="custom-block-title">HWP 파일 변환</p><p>공공기관 문서 등 서식이 중요한 경우, 변환 시 레이아웃이 달라질 수 있습니다. 원본은 반드시 보관하세요.</p></div><p><strong>그래도 안 되면:</strong> 한글 뷰어에서 텍스트를 복사하여 <code>.txt</code> 파일로 저장한 후 전달하세요.</p><hr><h2 id="대화-응답-문제" tabindex="-1">대화 &amp; 응답 문제 <a class="header-anchor" href="#대화-응답-문제" aria-label="Permalink to &quot;대화 &amp; 응답 문제&quot;">​</a></h2><h3 id="대화가-갑자기-끊겨요" tabindex="-1"><strong>대화가 갑자기 끊겨요</strong> <a class="header-anchor" href="#대화가-갑자기-끊겨요" aria-label="Permalink to &quot;**대화가 갑자기 끊겨요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>응답 도중 멈추거나, 대화가 중간에 끊기고 더 이상 진행되지 않음</td></tr><tr><td>원인</td><td>컨텍스트 윈도우(대화 길이 한도) 초과, 네트워크 일시 끊김, 서버 과부하</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>&quot;계속해줘&quot; 또는 &quot;이어서 작성해줘&quot;라고 입력하세요</li><li>네트워크 연결을 확인하세요</li><li>대화가 너무 길어졌다면(수십 회 이상), <strong>새 대화를 시작</strong>하고 핵심 맥락만 다시 전달하세요</li><li>큰 작업은 단계별로 나누어 요청하세요 (예: &quot;일단 1장만 써줘&quot;)</li></ol><p><strong>그래도 안 되면:</strong> 새 대화를 열고 이전 대화의 핵심 내용을 요약하여 전달한 후 이어서 작업하세요.</p><hr><h3 id="응답이-너무-느려요" tabindex="-1"><strong>응답이 너무 느려요</strong> <a class="header-anchor" href="#응답이-너무-느려요" aria-label="Permalink to &quot;**응답이 너무 느려요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>질문 후 응답이 나오기까지 수십 초 이상 걸리거나, 글자가 매우 천천히 표시됨</td></tr><tr><td>원인</td><td>서버 사용량 폭주, 대용량 파일 처리 중, 네트워크 속도 저하</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li><a href="https://status.anthropic.com" target="_blank" rel="noreferrer">status.anthropic.com</a>에서 서버 상태를 확인하세요</li><li>요청하는 작업의 범위를 줄여보세요 (파일 크기, 요청 분량 등)</li><li>피크 타임(한국 시간 오전 9~11시)을 피해 시도해 보세요</li><li>Wi-Fi 대신 유선 연결을 사용하거나, 다른 네트워크로 전환하세요</li><li>불필요한 백그라운드 프로그램을 종료하세요</li></ol><p><strong>그래도 안 되면:</strong> 잠시 후 다시 시도하세요. 지속적으로 느리다면 고객지원에 문의하세요.</p><hr><h3 id="이전-맥락을-기억-못-해요" tabindex="-1"><strong>이전 맥락을 기억 못 해요</strong> <a class="header-anchor" href="#이전-맥락을-기억-못-해요" aria-label="Permalink to &quot;**이전 맥락을 기억 못 해요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>&quot;아까 그거&quot;라고 했는데 못 알아듣거나, 이전에 알려준 내용을 모름</td></tr><tr><td>원인</td><td>새 대화 세션에서는 이전 대화 내용을 참조하지 못함, 대화가 너무 길어서 초기 내용이 잘림</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li><strong>같은 대화 세션</strong> 안에서 이어서 작업하세요 — 새 대화를 시작하면 기억이 초기화됩니다</li><li>새 대화에서 이어할 때는 필요한 맥락을 다시 알려주세요</li><li>프로젝트 설정 파일에 자주 쓰는 맥락 정보를 저장해 두세요</li><li>긴 대화에서 중요한 내용은 중간중간 요약을 요청하세요</li></ol><div class="tip custom-block"><p class="custom-block-title">맥락 전달 꿀팁</p><p>새 대화를 시작할 때 이렇게 말해보세요: &quot;이전 대화에서 3월 영업 보고서를 작성 중이었어. 목차는 이거고, 1장까지 완성했어. 이어서 2장을 작성해줘.&quot;</p></div><p><strong>그래도 안 되면:</strong> 중요한 대화 내용은 파일로 저장해두고, 새 대화에서 해당 파일을 참조하도록 요청하세요.</p><hr><h3 id="한국어-응답이-어색해요" tabindex="-1"><strong>한국어 응답이 어색해요</strong> <a class="header-anchor" href="#한국어-응답이-어색해요" aria-label="Permalink to &quot;**한국어 응답이 어색해요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>번역 투 표현, 부자연스러운 존댓말, 어색한 어미 사용</td></tr><tr><td>원인</td><td>구체적인 톤/스타일 지시 없이 요청, 영어 기반 학습 데이터의 영향</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>원하는 톤을 명시하세요: &quot;격식체로&quot;, &quot;~입니다 체로&quot;, &quot;친근한 반말로&quot;</li><li>대상을 알려주세요: &quot;팀장님께 보고할 문서&quot;, &quot;신입사원 교육용 자료&quot;</li><li>예시를 보여주세요: &quot;이런 느낌으로 써줘: [원하는 문장 예시]&quot;</li><li>어색한 부분을 짚어주세요: &quot;3번째 문단이 번역 투야. 자연스러운 한국어로 고쳐줘&quot;</li></ol><p><strong>그래도 안 되면:</strong> 초안을 받은 후 &quot;이 문서 전체를 자연스러운 비즈니스 한국어로 다듬어줘&quot;라고 요청하세요.</p><hr><h3 id="엉뚱한-답을-해요-할루시네이션" tabindex="-1"><strong>엉뚱한 답을 해요 (할루시네이션)</strong> <a class="header-anchor" href="#엉뚱한-답을-해요-할루시네이션" aria-label="Permalink to &quot;**엉뚱한 답을 해요 (할루시네이션)**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>그럴듯하지만 사실과 다른 정보를 자신 있게 말함, 존재하지 않는 출처 인용</td></tr><tr><td>원인</td><td>AI 모델의 본질적 한계, 학습 데이터에 없는 최신 정보 요청, 모호한 질문</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>구체적인 수치, 날짜, 법률 등은 반드시 <strong>별도로 사실 확인</strong>하세요</li><li>&quot;확실하지 않은 부분은 알려줘&quot;라고 미리 요청하세요</li><li>출처가 필요한 경우 &quot;출처를 함께 알려줘. 확실하지 않으면 확인이 필요하다고 표시해줘&quot;라고 말하세요</li><li>질문을 더 구체적으로 해 주세요 — 모호할수록 할루시네이션 가능성이 높아집니다</li><li>최신 정보가 필요하면 관련 자료를 파일로 전달하고 &quot;이 자료를 기반으로 답해줘&quot;라고 요청하세요</li></ol><div class="danger custom-block"><p class="custom-block-title">반드시 검증하세요</p><p>특히 다음 내용은 Claude의 답변을 그대로 신뢰하지 마세요:</p><ul><li>법률, 규정, 제도 관련 내용</li><li>특정 수치, 통계 데이터</li><li>인물의 발언 인용</li><li>&quot;~에 따르면&quot; 형태의 출처 언급</li></ul></div><p><strong>그래도 안 되면:</strong> 해당 주제에 대해 신뢰할 수 있는 자료를 직접 확인한 후, 그 자료를 Claude에게 전달하여 작업하세요.</p><hr><h2 id="기능-관련-문제" tabindex="-1">기능 관련 문제 <a class="header-anchor" href="#기능-관련-문제" aria-label="Permalink to &quot;기능 관련 문제&quot;">​</a></h2><h3 id="mcp-연동이-안-돼요" tabindex="-1"><strong>MCP 연동이 안 돼요</strong> <a class="header-anchor" href="#mcp-연동이-안-돼요" aria-label="Permalink to &quot;**MCP 연동이 안 돼요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>MCP 서버를 설정했는데 연결되지 않거나, 도구가 표시되지 않음</td></tr><tr><td>원인</td><td>설정 파일 오류, MCP 서버 미실행, 경로 설정 오류</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li><code>claude_desktop_config.json</code> 파일의 문법(JSON 형식)이 올바른지 확인하세요</li><li>MCP 서버 경로가 정확한지 확인하세요 — 오타가 가장 흔한 원인입니다</li><li>필요한 런타임(Node.js, Python 등)이 설치되어 있는지 확인하세요</li><li>Claude Desktop을 완전히 종료 후 재시작하세요 — 설정 파일은 시작 시에만 읽습니다</li><li>MCP 서버를 터미널에서 직접 실행하여 오류 메시지를 확인하세요</li></ol><div class="warning custom-block"><p class="custom-block-title">JSON 형식 주의</p><p>쉼표(<code>,</code>) 누락, 중괄호(<code>{}</code>) 짝 불일치가 가장 흔한 설정 오류입니다. JSON 검증 도구를 사용하여 문법을 확인하세요.</p></div><p><strong>그래도 안 되면:</strong> MCP 서버의 로그 파일을 확인하거나, 해당 MCP 도구의 공식 문서를 참고하세요.</p><hr><h3 id="플러그인이-작동하지-않아요" tabindex="-1"><strong>플러그인이 작동하지 않아요</strong> <a class="header-anchor" href="#플러그인이-작동하지-않아요" aria-label="Permalink to &quot;**플러그인이 작동하지 않아요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>설치한 플러그인이 목록에 표시되지 않거나, 사용 시 오류 발생</td></tr><tr><td>원인</td><td>플러그인 버전 호환성 문제, 설치 오류, 앱 버전이 오래됨</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>Claude Desktop을 최신 버전으로 업데이트하세요</li><li>플러그인을 삭제하고 다시 설치하세요</li><li>다른 플러그인과 충돌이 없는지 확인하세요 — 하나씩 비활성화하여 테스트</li><li>플러그인의 필수 의존성(다른 프로그램, 라이브러리 등)이 설치되어 있는지 확인하세요</li></ol><p><strong>그래도 안 되면:</strong> 해당 플러그인의 GitHub 이슈 페이지에서 비슷한 문제가 보고되었는지 확인하세요.</p><hr><h3 id="팀-공유가-안-돼요" tabindex="-1"><strong>팀 공유가 안 돼요</strong> <a class="header-anchor" href="#팀-공유가-안-돼요" aria-label="Permalink to &quot;**팀 공유가 안 돼요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>팀원에게 프로젝트나 대화를 공유하려는데 공유 옵션이 없거나 실패</td></tr><tr><td>원인</td><td>개인(Pro) 플랜 사용 중, 팀 설정 미완료, 팀원 초대 미완료</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>현재 플랜이 <strong>Team 이상</strong>인지 확인하세요 — 개인 Pro 플랜에서는 팀 공유가 제한됩니다</li><li>관리자 콘솔에서 팀원이 정상적으로 초대되었는지 확인하세요</li><li>공유 대상 팀원이 초대를 수락하고 계정 설정을 완료했는지 확인하세요</li><li>공유하려는 항목의 접근 권한 설정을 확인하세요</li></ol><p><strong>그래도 안 되면:</strong> 팀 관리자에게 팀 설정 상태 확인을 요청하세요.</p><hr><h3 id="예약-작업이-실행되지-않아요" tabindex="-1"><strong>예약 작업이 실행되지 않아요</strong> <a class="header-anchor" href="#예약-작업이-실행되지-않아요" aria-label="Permalink to &quot;**예약 작업이 실행되지 않아요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>예약한 자동 작업이 설정한 시간에 실행되지 않음</td></tr><tr><td>원인</td><td>컴퓨터가 꺼져 있거나 절전 모드, Claude Desktop 미실행, 예약 설정 오류</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>예약 시간에 컴퓨터가 <strong>켜져 있고 절전 모드가 아닌지</strong> 확인하세요</li><li>Claude Desktop이 실행 중인 상태여야 합니다 — 시작 프로그램에 등록하세요</li><li>예약 설정에서 시간대(Time Zone)가 **한국 시간(KST, UTC+9)**으로 되어 있는지 확인하세요</li><li>예약 작업을 삭제하고 다시 생성해 보세요</li></ol><p><strong>그래도 안 되면:</strong> 수동으로 해당 작업을 실행하여 작업 자체에 문제가 없는지 먼저 확인하세요.</p><hr><h2 id="계정-요금-문제" tabindex="-1">계정 &amp; 요금 문제 <a class="header-anchor" href="#계정-요금-문제" aria-label="Permalink to &quot;계정 &amp; 요금 문제&quot;">​</a></h2><h3 id="사용량-한도에-도달했어요" tabindex="-1"><strong>사용량 한도에 도달했어요</strong> <a class="header-anchor" href="#사용량-한도에-도달했어요" aria-label="Permalink to &quot;**사용량 한도에 도달했어요**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>&quot;사용량 한도에 도달했습니다&quot; 메시지가 표시되고 더 이상 응답하지 않음</td></tr><tr><td>원인</td><td>현재 플랜의 일일/월별 사용량 제한 초과</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li>현재 사용량을 설정 → 사용량(Usage)에서 확인하세요</li><li>한도 초기화 시점을 확인하세요 (보통 매일 또는 매월 갱신)</li><li>급한 작업이 있다면 플랜 업그레이드를 고려하세요</li><li>불필요하게 긴 대화나 반복 요청을 줄이면 사용량을 절약할 수 있습니다</li></ol><table tabindex="0"><thead><tr><th>플랜</th><th>사용량 한도</th><th>초기화 주기</th></tr></thead><tbody><tr><td>무료</td><td>매우 제한적</td><td>매일</td></tr><tr><td>Pro</td><td>넉넉함</td><td>매일</td></tr><tr><td>Team</td><td>팀원별 할당</td><td>매월</td></tr><tr><td>Enterprise</td><td>맞춤 설정</td><td>계약에 따름</td></tr></tbody></table><p><strong>그래도 안 되면:</strong> 플랜 업그레이드를 진행하거나, 한도 초기화 시점까지 기다리세요.</p><hr><h3 id="플랜-업그레이드-방법" tabindex="-1"><strong>플랜 업그레이드 방법</strong> <a class="header-anchor" href="#플랜-업그레이드-방법" aria-label="Permalink to &quot;**플랜 업그레이드 방법**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>더 많은 기능이나 사용량이 필요하여 플랜을 변경하고 싶음</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li><a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a>에 로그인하세요</li><li>설정(Settings) → 요금제(Subscription)로 이동하세요</li><li>원하는 플랜을 선택하고 결제 정보를 입력하세요</li><li>업그레이드는 즉시 적용되며, 기존 결제 주기에 비례하여 청구됩니다</li></ol><div class="tip custom-block"><p class="custom-block-title">회사에서 도입하는 경우</p><p>Team/Enterprise 플랜은 관리자가 중앙에서 관리합니다. 개인이 별도 결제하지 말고, 회사 관리자에게 요청하세요.</p></div><p><strong>그래도 안 되면:</strong> 결제 관련 문제는 <a href="https://support.anthropic.com" target="_blank" rel="noreferrer">support.anthropic.com</a>에 문의하세요.</p><hr><h3 id="팀-멤버-추가-방법" tabindex="-1"><strong>팀 멤버 추가 방법</strong> <a class="header-anchor" href="#팀-멤버-추가-방법" aria-label="Permalink to &quot;**팀 멤버 추가 방법**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>증상</td><td>새로운 팀원을 Cowork에 추가하고 싶음</td></tr></tbody></table><p><strong>해결 방법:</strong></p><ol><li><strong>관리자 계정</strong>으로 <a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a>에 로그인하세요</li><li>관리자 콘솔(Admin Console) → 팀원 관리(Members)로 이동하세요</li><li>&quot;초대하기(Invite)&quot; 버튼을 클릭하세요</li><li>팀원의 <strong>회사 이메일 주소</strong>를 입력하고 역할(관리자/멤버)을 설정하세요</li><li>초대된 팀원이 이메일의 링크를 클릭하여 가입을 완료하면 사용 가능합니다</li></ol><div class="warning custom-block"><p class="custom-block-title">권한 관리</p><p>관리자(Admin) 역할은 팀 설정 변경, 멤버 추가/삭제가 가능합니다. 필요한 인원에게만 관리자 권한을 부여하세요.</p></div><p><strong>그래도 안 되면:</strong> Team/Enterprise 플랜의 좌석(seat) 수가 부족할 수 있습니다. 관리자 콘솔에서 잔여 좌석을 확인하거나 추가 구매하세요.</p><hr><h2 id="도움-요청하기" tabindex="-1">도움 요청하기 <a class="header-anchor" href="#도움-요청하기" aria-label="Permalink to &quot;도움 요청하기&quot;">​</a></h2><p>위의 방법으로도 해결되지 않는다면, 아래 채널을 통해 도움을 받으세요.</p><table tabindex="0"><thead><tr><th>지원 채널</th><th>대상</th><th>응답 시간</th></tr></thead><tbody><tr><td><a href="https://support.anthropic.com" target="_blank" rel="noreferrer">support.anthropic.com</a></td><td>모든 사용자</td><td>1~2 영업일</td></tr><tr><td>사내 IT 헬프데스크</td><td>설치/네트워크 문제</td><td>당일</td></tr><tr><td>팀 관리자</td><td>계정/권한 문제</td><td>즉시</td></tr><tr><td><a href="https://community.anthropic.com" target="_blank" rel="noreferrer">Anthropic 커뮤니티</a></td><td>활용 팁, 동료 사용자 질문</td><td>다양함</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">문의 시 포함할 정보</p><p>문제를 빠르게 해결하려면 다음 정보를 함께 전달하세요:</p><ul><li><strong>오류 메시지</strong> 전문 (스크린샷 첨부)</li><li><strong>Claude Desktop 버전</strong> (설정 → 정보에서 확인)</li><li><strong>운영체제</strong> 및 버전 (Windows 11, macOS 등)</li><li><strong>문제 발생 시점</strong> 및 재현 방법</li><li><strong>시도한 해결 방법</strong></li></ul></div>',149)])])}const u=o(d,[["render",e]]);export{b as __pageData,u as default};
